{
  "sentences": [
    {
      "text": "從我家到車站要十分鐘。",
      "pinyin": "Cóng wǒ jiā dào chē zhàn yào shí fēn zhōng.",
      "pinyin_numeric": "cong2 wo3 jia1 dao4 che1 zhan4 yao4 shi2 fen1 zhong1",
      "translation_en": "It takes ten minutes from my home to the station.",
      "translation_ko": "우리 집에서 역까지 10분 걸려요."
    },
    {
      "text": "到台北車站要坐捷運嗎？",
      "pinyin": "Dào Tái běi chē zhàn yào zuò jié yùn ma?",
      "pinyin_numeric": "dao4 Tai2 bei3 che1 zhan4 yao4 zuo4 jie2 yun4 ma0",
      "translation_en": "Do I need to take the MRT to get to Taipei Station?",
      "translation_ko": "타이베이 역까지 지하철을 타야 하나요?"
    },
    {
      "text": "從這裡到公園走路要五分鐘。",
      "pinyin": "Cóng zhè lǐ dào gōng yuán zǒu lù yào wǔ fēn zhōng.",
      "pinyin_numeric": "cong2 zhe4 li3 dao4 gong1 yuan2 zou3 lu4 yao4 wu3 fen1 zhong1",
      "translation_en": "It takes five minutes to walk from here to the park.",
      "translation_ko": "여기에서 공원까지 걸어서 5분 걸려요."
    },
    {
      "text": "到醫院坐計程車要二十分鐘。",
      "pinyin": "Dào yī yuàn zuò jì chéng chē yào èr shí fēn zhōng.",
      "pinyin_numeric": "dao4 yi1 yuan4 zuo4 ji4 cheng2 che1 yao4 er4 shi2 fen1 zhong1",
      "translation_en": "It takes twenty minutes to get to the hospital by taxi.",
      "translation_ko": "병원까지 택시로 20분 걸려요."
    },
    {
      "text": "從學校到圖書館要幾分鐘？",
      "pinyin": "Cóng xué xiào dào tú shū guǎn yào jǐ fēn zhōng?",
      "pinyin_numeric": "cong2 xue2 xiao4 dao4 tu2 shu1 guan3 yao4 ji3 fen1 zhong1",
      "translation_en": "How many minutes does it take from school to the library?",
      "translation_ko": "학교에서 도서관까지 몇 분 걸리나요?"
    },
    {
      "text": "到捷運站走路要十五分鐘。",
      "pinyin": "Dào jié yùn zhàn zǒu lù yào shí wǔ fēn zhōng.",
      "pinyin_numeric": "dao4 jie2 yun4 zhan4 zou3 lu4 yao4 shi2 wu3 fen1 zhong1",
      "translation_en": "It takes fifteen minutes to walk to the MRT station.",
      "translation_ko": "지하철역까지 걸어서 15분 걸려요."
    },
    {
      "text": "從公司到餐廳坐公車要三十分鐘。",
      "pinyin": "Cóng gōng sī dào cān tīng zuò gōng chē yào sān shí fēn zhōng.",
      "pinyin_numeric": "cong2 gong1 si1 dao4 can1 ting1 zuo4 gong1 che1 yao4 san1 shi2 fen1 zhong1",
      "translation_en": "It takes thirty minutes from the office to the restaurant by bus.",
      "translation_ko": "회사에서 식당까지 버스로 30분 걸려요."
    },
    {
      "text": "到夜市坐公車要二十分鐘嗎？",
      "pinyin": "Dào yè shì zuò gōng chē yào èr shí fēn zhōng ma?",
      "pinyin_numeric": "dao4 ye4 shi4 zuo4 gong1 che1 yao4 er4 shi2 fen1 zhong1 ma0",
      "translation_en": "Does it take twenty minutes to get to the night market by bus?",
      "translation_ko": "야시장까지 버스로 20분 걸리나요?"
    },
    {
      "text": "從這裡到咖啡店走路要三分鐘。",
      "pinyin": "Cóng zhè lǐ dào kā fēi diàn zǒu lù yào sān fēn zhōng.",
      "pinyin_numeric": "cong2 zhe4 li3 dao4 ka1 fei1 dian4 zou3 lu4 yao4 san1 fen1 zhong1",
      "translation_en": "It takes three minutes to walk from here to the coffee shop.",
      "translation_ko": "여기에서 커피숍까지 걸어서 3분 걸려요."
    },
    {
      "text": "到學校坐捷運要二十五分鐘。",
      "pinyin": "Dào xué xiào zuò jié yùn yào èr shí wǔ fēn zhōng.",
      "pinyin_numeric": "dao4 xue2 xiao4 zuo4 jie2 yun4 yao4 er4 shi2 wu3 fen1 zhong1",
      "translation_en": "It takes twenty-five minutes to get to school by MRT.",
      "translation_ko": "학교까지 지하철로 25분 걸려요."
    }
  ]
}
